class Solution {
public:
    int maxPalindromes(string s, int k) {
        int n = s.size();
        vector<bool> isPal(n, false);
        for (int i = 0; i < n; ++i) {
            int l = i, r = i;
            while (l >= 0 && r < n && s[l] == s[r]) {
                if (r - l + 1 >= k) isPal[r] = true;
                --l; ++r;
            }
            l = i; r = i + 1;
            while (l >= 0 && r < n && s[l] == s[r]) {
                if (r - l + 1 >= k) isPal[r] = true;
                --l; ++r;
            }
        }
        int count = 0, prev = -1;
        for (int i = 0; i < n; ++i) {
            if (isPal[i] && i - k + 1 > prev) {
                ++count;
                prev = i;
            }
        }
        return count;
    }
};
